/**
 * Compatibility barrel for frontend types.
 *
 * Every struct-like type here is a re-export of the generated Specta binding
 * (the camelCase `_Serialize` projection or the plain generated type). There is
 * no hand-written struct universe anymore — the generated bindings are the
 * single source of truth for shape and field naming (spec 042 SC-002 / T268).
 *
 * Genuinely frontend-only types (no backend DTO / not generated by Specta) live
 * in `@/types/frontend` and are re-exported at the bottom of this file so that
 * existing `@/bindings/types` import sites keep working.
 */

// ─── Enum / String-Union Re-exports ─────────────────────────────────────────

// Spec 041 FR-051 (T076, Phase 13): `SessionState` was removed — sessions
// are derived, already-confirmed inventory with no review-state machine.
export type {
  ProjectState,
  ConfidenceLevel,
  ProvenanceOrigin,
  ViewMode,
  Density,
  CalibrationKind,
  PlanItemAction,
  PlanItemState,
  PlanItemProtection,
  PlanOrigin,
  PlanType,
  DestructiveDestination,
  AuditOutcome,
  ReviewItemKind,
  SearchResultKind,
  RootCategory,
  // Spec 041: per-source organization state (move vs catalogue).
  OrganizationState,
  // Spec 008: project source role + selection (canonical in projects_v2.rs)
  SourceRole,
  SourceSelection,
  // SourceViewStrategy — moved to spec 026 (generated source views); remove this
  //   re-export when spec 026 registers its command and emits the type.
  // OutputVerification  — moved to spec 012 (artifact verification); same.
  // CleanupEligibility  — moved to spec 017 cleanup planner; same.
  SessionsGroupBy,
  SessionsView,
  TransitionActor,
  TransitionStatus,
  AuditActor,
  AssetType,
  // Plan response types
  PlanApproveResponse,
  PlanDiscardResponse,
  PlanRetryResponse,
  ArchiveSendToTrashResponse,
  ArchivePermanentlyDeleteResponse,
} from './index';

/**
 * PlanState — re-export from generated bindings. Includes `"paused"` (spec 017
 * data-model.md §PlanState, R-Pause-1) now that it is surfaced in the Rust
 * contracts `PlanState` enum.
 */
export type PlanState = import('./index').PlanState;

// ─── Struct Re-exports (generated _Serialize / plain bindings) ───────────────
//
// Each type below re-exports its generated Specta binding. Consumers and the
// generated bindings share one structural (camelCase) type — there are no
// hand-written struct duplicates (spec 042 SC-002).

/** Re-export generated type so callers continue to import from '@/bindings/types'. */
export type MetaValue = import('./index').MetaValue_Serialize;

/** Re-export generated type (already camelCase). */
export type AppPreferences = import('./index').AppPreferences;

/** Re-export generated type (`{ scope, values }`). */
export type SettingsData = import('./index').SettingsData;

