// Long-operation contract event (spec 042 US16, T240). Streamed live over a
// `Channel<OperationEvent>` from the plan-apply command. Re-exported from the
// generated bindings so feature code imports it through the friendly facade.
export type OperationEvent = import('./index').OperationEvent;
export type OperationEventType = import('./index').OperationEventType;

// Frontend-only types (no backend DTO / not generated by Specta) live in
// `@/types/frontend`; re-exported here so existing `@/bindings/types` import
// sites keep working (spec 042 T268).
export type {
  SourceMap,
  ProjectSource,
  ProjectSourceView,
  ProjectOutput,
  ProjectArtifactGroup,
  ProgressEvent,
} from '@/types/frontend';

// Catalog distribution types (spec 014) were removed: target resolution now uses
// the SIMBAD on-demand resolver + bundled seed + local cache (spec 035). The
// hosted/downloaded signed-catalog backend commands no longer exist.
